function getMunicipioFromCoords(lat, lon){
  // Buscar en grid 3x3 celdas alrededor del punto
  let best=null, bestDist=Infinity;
  for(let dlat=-1;dlat<=1;dlat++){
    for(let dlon=-2;dlon<=2;dlon++){
      const key=`${Math.floor(lat+dlat)}_${Math.floor(lon+dlon)}`;
      (MGRID[key]||[]).forEach(i=>{
        const m=MUNIS[i];
        const d=(lat-m.la)**2+(lon-m.lo)**2;
        if(d<bestDist){bestDist=d;best=m;}
      });
    }
  }
  // Fallback: buscar en todo si no se encontró nada cerca
  if(!best||bestDist>4){
    MUNIS.forEach(m=>{
      const d=(lat-m.la)**2+(lon-m.lo)**2;
      if(d<bestDist){bestDist=d;best=m;}
    });
  }
  return best;
}
